def count_max_or_subsets(nums):
    max_OR = 0
    for num in nums:
        max_OR |= num

    OR_subsets = {0}
    for num in nums:
        tmp = OR_subsets.copy()
        for x in OR_subsets:
            tmp.add(x | num)
        OR_subsets = tmp

    return OR_subsets.count(max_OR)
```


