import java.util.HashSet;
import java.util.Set;

public int countMaxOrSubsets(int[] nums) {
    int max_OR = 0;
    for(int num : nums) {
        max_OR |= num;
    }

    Set<Integer> OR_subsets = new HashSet<>();
    OR_subsets.add(0);

    for(int num : nums) {
        Set<Integer> tmp = new HashSet<>(OR_subsets);
        for(int x : OR_subsets) {
            tmp.add(x | num);
        }
        OR_subsets = tmp;
    }

    int count = 0;
    for(int x : OR_subsets) {
        if(x == max_OR) {
            count++;
        }
    }
    return count;
}
